mapper.select:
SELECT c.coachId,c.coachName,cps.grade,c.level,c.minClassMoney,c.classCount, c.headImgUrl, (select u.userSign from user_info u where u.userId=c.userId limit 1) as introduce FROM coach_place_ship cps LEFT JOIN coach c ON c.coachId = cps.coachId WHERE 1=1
AND cps.storeId=#{storeId}
AND cps.grade=#{grade}
ORDER BY c.level DESC
limit #{offset}, #{limit}

SELECT count(*) FROM coach_place_ship cps LEFT JOIN coach c ON c.coachId = cps.coachId WHERE 1=1
AND cps.storeId=#{storeId}
AND cps.grade=#{grade}

SELECT concat(g.price,'') as classFee,p.firstImgUrl,p.className,p.privateClassId as classId
from grade_price_ship g LEFT JOIN private_class p ON p.privateClassId = g.privateClassId
WHERE g.grade  <=  #{grade}

SELECT storeId FROM coach_place_ship WHERE coachId = #{coachId} AND  grade <> 2 
AND storeId IN

    #{item}
